import React from 'react';
import _ from 'lodash';
import {
  Autocomplete,
  Button,
  TextField,
  Box,
  Typography,
  Paper,
  Grid,
  Card,
  CardContent,
  Divider,
  Stack,
  Avatar,
  Chip,
  useTheme,
  InputAdornment,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
} from '@mui/material';
import {
  CalendarToday as CalendarIcon,
  Receipt as ReceiptIcon,
  AccountBalance as BankIcon,
  Person as PersonIcon,
  AttachMoney as MoneyIcon,
  Assignment as ProjectIcon,
  Save as SaveIcon,
} from '@mui/icons-material';
import DatePicker from '@mui/lab/DatePicker';
import LocalizationProvider from '@mui/lab/LocalizationProvider';
import AdapterDateFns from '@mui/lab/AdapterDateFns';
import { createFilterOptions } from '@mui/material/Autocomplete';

export default function ExpensesApplyForm({
  expenses,
  control,
  Controller,
  date,
  setDate,
  paidType,
  setPaidType,
  projects,
  projectSelect,
  setProjectSelect,
  setValue,
  setBudgetSelect,
  bank,
  setBank,
  customer,
  onAddCustomer,
  setCustomerSelect,
  budgetSelect,
}) {
  const theme = useTheme();
  const filter = createFilterOptions();

  const handleCheckLevel = (data) => {
    const each = _.find(projects?.rows, { _id: data?._id });
    setValue('project', each?._id);
    setProjectSelect(each);
    // --- เคลียร์ค่างบประมาณเมื่อเปลี่ยนโปรเจค ---
    setValue('budget', null);
    if (typeof setBudgetSelect === 'function') {
      setBudgetSelect(null);
    }
  };

  const handleCheckBudget = (data) => {
    const each = _.find(projectSelect?.budget, { _id: data?._id });
    setValue('budget', each?._id);
    setBudgetSelect(each);
  };

  const handleAdd = (inputValue, fieldName) => {
    if (onAddCustomer && inputValue) onAddCustomer(inputValue, fieldName);
  };

  const handleCheckPayee = (data) => {
    const each = _.find(customer?.rows, { _id: data?._id });
    setValue('customer', each?._id);
    setValue('payee.bank', each?.bank?.bank_name || '');
    setValue('payee.name', each?.bank?.account_name || '');
    setValue('payee.account_number', each?.bank?.account_number || '');
    if (typeof setCustomerSelect === 'function') setCustomerSelect(each);
  };

  return (
    <Box sx={{ maxWidth: 1000, mx: 'auto', p: { xs: 2, md: 3 } }}>
      <Card
        elevation={0}
        sx={{ borderRadius: 3, border: '1px solid', borderColor: 'divider' }}
      >
        <CardContent sx={{ p: { xs: 2, md: 3 } }}>
          <Grid container spacing={2}>
            <Grid item xs={12} md={8}>
              <Typography variant="subtitle2" sx={{ mb: 1, fontWeight: 600 }}>
                โครงการ
              </Typography>
              <Controller
                name="project"
                control={control}
                render={({ field }) => (
                  <Autocomplete
                    {...field}
                    disablePortal
                    freeSolo
                    options={projects?.rows || []}
                    getOptionLabel={(option) =>
                      `${option.project_number}|ลูกค้า: ${option.customer} | ${option.name}`
                    }
                    onChange={(e, newValue) => handleCheckLevel(newValue)}
                    renderInput={(params) => (
                      <TextField
                        {...params}
                        size="small"
                        fullWidth
                        InputProps={{
                          ...params.InputProps,
                          startAdornment: (
                            <InputAdornment position="start">
                              <ProjectIcon fontSize="small" />
                            </InputAdornment>
                          ),
                        }}
                      />
                    )}
                  />
                )}
              />
            </Grid>

            <Grid item xs={12} md={4}>
              <Typography variant="subtitle2" sx={{ mb: 1, fontWeight: 600 }}>
                งบประมาณ
              </Typography>
              <Controller
                name="budget"
                control={control}
                render={({ field }) => (
                  <Autocomplete
                    {...field}
                    disablePortal
                    freeSolo
                    disabled={!projectSelect} // --- ปิดการใช้งานถ้ายังไม่เลือกโปรเจค ---
                    options={projectSelect?.budget || []}
                    getOptionLabel={(option) =>
                      `${option.prefix || ''}${option.budget_number} | ${
                        option.name
                      }`
                    }
                    onChange={(e, newValue) => handleCheckBudget(newValue)}
                    renderInput={(params) => (
                      <TextField {...params} size="small" fullWidth />
                    )}
                  />
                )}
              />
            </Grid>

            <Grid item xs={12} md={6}>
              <Typography variant="subtitle2" sx={{ mb: 1, fontWeight: 600 }}>
                วันที่ขอ รับเงิน/จ่ายเงิน
              </Typography>
              <LocalizationProvider dateAdapter={AdapterDateFns}>
                <DatePicker
                  label="MM/DD/YYYY"
                  value={date}
                  fullWidth
                  onChange={(newDate) => setDate(newDate)}
                  renderInput={(params) => <TextField fullWidth {...params} />}
                />
              </LocalizationProvider>
            </Grid>

            {/* <Grid item xs={12} md={6}>
              <Typography variant="subtitle2" sx={{ mb: 1, fontWeight: 600 }}>
                หมายเลข/อ้างอิง
              </Typography>
              <Controller
                name="invoice_number"
                control={control}
                defaultValue=""
                render={({ field }) => (
                  <TextField
                    {...field}
                    size="small"
                    fullWidth
                    placeholder="หมายเลขใบแจ้งหนี้ (ถ้ามี)"
                  />
                )}
              />
            </Grid> */}

            <Grid item xs={12} md={6}>
              <Typography variant="subtitle2" sx={{ mb: 1, fontWeight: 600 }}>
                ประเภทการเบิก
              </Typography>
              <Controller
                name="expenses_type"
                control={control}
                defaultValue={paidType || 'REFUND'}
                render={({ field }) => (
                  <FormControl fullWidth size="small">
                    <InputLabel id="paid-type-label">ประเภทการเบิก</InputLabel>
                    <Select
                      labelId="paid-type-label"
                      label="ประเภทการเบิก"
                      {...field}
                    >
                      <MenuItem value="PAY">เบิกเพื่อจ่าย</MenuItem>
                      <MenuItem value="REFUND">เบิกคืน</MenuItem>
                    </Select>
                  </FormControl>
                )}
              />
            </Grid>

            <Grid item xs={12} md={8}>
              <Typography variant="subtitle2" sx={{ mb: 1, fontWeight: 600 }}>
                รายการ
              </Typography>
              <Controller
                name="name"
                control={control}
                defaultValue={expenses ? expenses?.name : ''}
                rules={{
                  required: 'กรุณาระบุรายการ',
                  maxLength: { value: 255, message: 'ความยาวต้องไม่เกิน 255' },
                }}
                render={({ field, fieldState: { error } }) => (
                  <TextField
                    {...field}
                    size="small"
                    fullWidth
                    multiline
                    rows={2}
                    error={!!error}
                    helperText={
                      error ? error.message : `${field.value?.length || 0}/255`
                    }
                  />
                )}
              />
            </Grid>

            <Grid item xs={12} md={4}>
              <Typography variant="subtitle2" sx={{ mb: 1, fontWeight: 600 }}>
                จำนวนเงิน
              </Typography>
              <Controller
                name="price"
                control={control}
                defaultValue={expenses ? expenses?.price : ''}
                rules={{ required: 'กรุณาระบุจำนวน' }}
                render={({ field, fieldState: { error } }) => (
                  <TextField
                    {...field}
                    size="small"
                    fullWidth
                    type="number"
                    InputProps={{
                      startAdornment: (
                        <InputAdornment position="start">฿</InputAdornment>
                      ),
                    }}
                    error={!!error}
                    helperText={error ? error.message : ''}
                  />
                )}
              />
            </Grid>

            <Grid item xs={12}>
              <Divider sx={{ my: 1 }} />
            </Grid>

            <Grid item xs={12} md={6}>
              <Typography variant="subtitle2" sx={{ mb: 1, fontWeight: 600 }}>
                ผู้รับเงิน
              </Typography>
              <Controller
                name="customer"
                control={control}
                render={({ field }) => (
                  <Autocomplete
                    {...field}
                    freeSolo
                    disablePortal
                    options={customer?.rows || []}
                    getOptionLabel={(option) => `${option?.name || ''}`}
                    filterOptions={(options, params) => {
                      const filtered = filter(options, params);
                      const { inputValue } = params;
                      const isExisting = options.some(
                        (option) =>
                          `${option?.name}`.toLowerCase() ===
                          inputValue.toLowerCase(),
                      );
                      if (inputValue !== '' && !isExisting) {
                        filtered.push({
                          inputValue,
                          name: inputValue,
                          isAddNew: true,
                        });
                      }
                      return filtered;
                    }}
                    onChange={(e, newValue) => {
                      if (typeof newValue === 'string')
                        handleAdd(newValue, 'bank');
                      else if (newValue?.isAddNew)
                        handleAdd(newValue.inputValue, 'bank');
                      else handleCheckPayee(newValue);
                    }}
                    renderOption={(props, option) =>
                      option.isAddNew ? (
                        <li {...props}>เพิ่ม "{option.inputValue}"</li>
                      ) : (
                        <li {...props}>{option.name}</li>
                      )
                    }
                    renderInput={(params) => (
                      <TextField {...params} size="small" fullWidth />
                    )}
                  />
                )}
              />
            </Grid>

            <Grid item xs={12} md={6}>
              <Typography variant="subtitle2" sx={{ mb: 1, fontWeight: 600 }}>
                ข้อมูลบัญชี
              </Typography>
              <Grid container spacing={1}>
                <Grid item xs={12} sm={6}>
                  <Controller
                    name="payee.bank"
                    control={control}
                    defaultValue=""
                    render={({ field }) => (
                      <TextField
                        {...field}
                        size="small"
                        fullWidth
                        label="ธนาคาร"
                        disabled
                      />
                    )}
                  />
                </Grid>
                <Grid item xs={12} sm={6}>
                  <Controller
                    name="payee.account_number"
                    control={control}
                    defaultValue=""
                    render={({ field }) => (
                      <TextField
                        {...field}
                        size="small"
                        fullWidth
                        label="เลขที่บัญชี"
                        disabled
                      />
                    )}
                  />
                </Grid>
                <Grid item xs={12}>
                  <Controller
                    name="payee.name"
                    control={control}
                    defaultValue=""
                    render={({ field }) => (
                      <TextField
                        {...field}
                        size="small"
                        fullWidth
                        label="ชื่อบัญชี"
                        disabled
                      />
                    )}
                  />
                </Grid>
              </Grid>
            </Grid>
          </Grid>

          <Box sx={{ display: 'flex', justifyContent: 'flex-end', mt: 3 }}>
            <Button
              variant="contained"
              color="primary"
              size="large"
              startIcon={<SaveIcon />}
              type="submit"
              sx={{
                borderRadius: 2,
                px: 4,
                py: 1.5,
              }}
            >
              บันทึก
            </Button>
          </Box>
        </CardContent>
      </Card>
    </Box>
  );
}
