import React, { useState } from 'react';
import {
  NavLink as RouterLink,
  matchPath,
  useLocation,
  useHistory,
} from 'react-router-dom';
import PropTypes from 'prop-types';
import { Collapse, List, ListItemButton, Accordion } from '@mui/material';
import { ChevronRight, ChevronDown } from 'react-feather';
import _ from 'lodash';
import accessRight from '../../utils/functions/accessRight';

const NavItem = ({ href, icon: Icon, title, sub, moduleName, me }) => {
  const history = useHistory();
  const location = useLocation();
  const active = href
    ? !!matchPath(location.pathname, {
        path: href,
      })
    : false;
  const [open, setOpen] = useState(active);

  const handleClick = () => {
    setOpen(!open);
    history.push(href);
  };

  return (
    <div className="py-1">
      <Accordion
        elevation={0}
        expanded={open}
        onClick={() => {
          handleClick();
        }}
        sx={{
          borderRadius: 1,
          '&:before': { display: 'none' },
          ...(active && {
            color: 'primary.main',
            backgroundColor: 'rgba(25, 118, 210, 0.08)',
            fontWeight: 'fontWeightBold',
            '& .MuiSvgIcon-root': {
              color: 'primary.main',
            },
          }),
          ...(!active && {
            color: 'text.secondary',
            backgroundColor: 'transparent',
            '&:hover': {
              backgroundColor: 'rgba(0, 0, 0, 0.04)',
              color: 'text.primary',
            },
          }),
        }}
        TransitionProps={{ unmountOnExit: true }}
        className="px-2 cursor-pointer"
      >
        <div className="flex gap-2 items-center py-2">
          {Icon && <Icon size="20" />}
          <span>{title}</span>
          {_.size(sub) ? (
            <div className="ml-auto">
              {open ? <ChevronDown size="16" /> : <ChevronRight size="16" />}
            </div>
          ) : (
            <></>
          )}
        </div>
      </Accordion>
      {_.size(sub) ? (
        <Collapse in={open} timeout="auto" unmountOnExit>
          {_.map(sub, (item, index) => {
            if (accessRight(me, moduleName, item.level)) {
              return (
                <div key={index}>
                  <List component="div" disablePadding>
                    <ListItemButton
                      component={RouterLink}
                      to={item.href}
                      sx={{
                        pl: 4,
                        borderRadius: 1,
                        mt: 0.5,
                        ...(item.href === location.pathname && {
                          color: 'primary.main',
                          backgroundColor: 'rgba(25, 118, 210, 0.08)',
                        }),
                        ...(!(item.href === location.pathname) && {
                          color: 'text.secondary',
                          '&:hover': {
                            backgroundColor: 'rgba(0, 0, 0, 0.04)',
                            color: 'text.primary',
                          },
                        }),
                      }}
                    >
                      <div
                        className={`font-light text-sm ${
                          item.href === location.pathname ? 'font-medium' : ''
                        }`}
                      >
                        {item.title}
                      </div>
                    </ListItemButton>
                  </List>
                </div>
              );
            }
            return <></>;
          })}
        </Collapse>
      ) : (
        <></>
      )}
    </div>
  );
};

NavItem.propTypes = {
  href: PropTypes.string,
  icon: PropTypes.elementType,
  title: PropTypes.string,
  sub: PropTypes.array,
  me: PropTypes.object,
  moduleName: PropTypes.string,
};

export default NavItem;
